public boolean insertEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret = next insertEntityDataSource(_entityCtx, _dataSourceCtx);

    if(ret && ETGACFParameters::find().EnableDMSIntegration == NoYes::Yes)
    {
        if (_entityCtx.getDatabaseOperation() == DataEntityDatabaseOperation::Insert || DataEntityDatabaseOperation::Update)
        {
            switch (_dataSourceCtx.name())
            {
                case dataEntityDataSourceStr(WMSWarehouseLocationEntity, WMSLocation):

                    if (!InventLocation::find(this.WarehouseId, false).RecId)
                    {
                        InventLocation newLoc;
                        newLoc.InventLocationId = this.WarehouseId;
                        newLoc.Name = this.WarehouseId;
                        newLoc.insert();
                    }
                    break;
            }
        }
    }
    return ret;
}
